// A much simpler Netlify function that doesn't rely on file system access

// This is our static extension file encoded as base64
// For a real implementation, you would replace this with your actual extension file encoded as base64
// You can generate this by running: base64 -w 0 your-extension.zip
// arquivo em /src/assets/extension/base64.txt
// comando para criar o base 64
// base64 -w 0 extencao-disparo-rapido.zip > base64.txt
const EXTENSION_BASE64 = ""


export const handler = async (event, context) => {
  // Handle CORS preflight requests
  if (event.httpMethod === 'OPTIONS') {
    return {
      statusCode: 200,
      headers: {
        'Access-Control-Allow-Origin': '*',
        'Access-Control-Allow-Headers': 'Content-Type, X-Secure-Request',
        'Access-Control-Allow-Methods': 'POST, OPTIONS',
        'Access-Control-Max-Age': '86400'
      },
      body: ''
    };
  }
  
  // Only allow POST requests
  if (event.httpMethod !== 'POST') {
    return {
      statusCode: 405,
      headers: {
        'Access-Control-Allow-Origin': '*',
      },
      body: JSON.stringify({ message: 'Method Not Allowed' }),
    };
  }

  // Check for security header
  const secureHeader = event.headers['x-secure-request'];
  if (!secureHeader || secureHeader !== 'true') {
    return {
      statusCode: 403,
      headers: {
        'Access-Control-Allow-Origin': '*',
      },
      body: JSON.stringify({ message: 'Unauthorized access' }),
    };
  }

  try {
    // Return the static file data
    return {
      statusCode: 200,
      headers: {
        'Content-Type': 'application/json',
        'Access-Control-Allow-Origin': '*',
        'Access-Control-Allow-Headers': 'Content-Type, X-Secure-Request'
      },
      body: JSON.stringify({
        fileData: EXTENSION_BASE64,
        fileName: 'extencao-disparo-rapido.zip',
        fileType: 'application/zip'
      }),
    };
  } catch (error) {
    console.error('Error:', error);
    return {
      statusCode: 500,
      headers: {
        'Access-Control-Allow-Origin': '*',
      },
      body: JSON.stringify({ 
        message: 'Internal server error', 
        error: error.message
      }),
    };
  }
}
